'use client';

import { useRef, useState } from 'react';
import { motion } from 'framer-motion';

export default function SplitText({
  text,
  className,
  delay = 100,
  duration = 0.6,
  ease = 'easeOut',
  splitType = 'chars',
  from = { opacity: 0, y: 40 },
  to = { opacity: 1, y: 0 },
  threshold = 0.1,
  rootMargin = '-100px',
  textAlign = 'center',
  onLetterAnimationComplete,
}) {
  const delaySec = delay / 1000;
  const parts = splitType === 'words' ? text.split(' ') : Array.from(text);
  const completed = useRef(0);
  const [total] = useState(parts.length);

  const handleComplete = () => {
    completed.current += 1;
    if (completed.current === total && typeof onLetterAnimationComplete === 'function') {
      onLetterAnimationComplete();
    }
  };

  return (
    <span className={className} style={{ display: 'inline-block', textAlign }}>
      {parts.map((p, i) => (
        <motion.span
          key={`${p}-${i}`}
          initial={from}
          whileInView={to}
          viewport={{ once: true, amount: threshold, margin: rootMargin }}
          transition={{ duration, delay: i * delaySec, ease }}
          style={{ display: 'inline-block' }}
          onAnimationComplete={handleComplete}
        >
          {splitType === 'words' ? `${p} ` : p}
        </motion.span>
      ))}
    </span>
  );
}

